module EEPROM_Cell (  
    input clk,  
    input rst,  
    input [7:0] data_in,  
    input read,  
    input write,  
    input erase,  
    output reg [7:0] data_out  
);  

    reg [7:0] cell_data;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            cell_data <= 8'b0;  
            data_out <= 8'b0;  
        end else begin  
            if (erase) begin  
                cell_data <= 8'b0;  
            end else if (write) begin  
                cell_data <= data_in;  
            end else if (read) begin  
                data_out <= cell_data;  
            end  
        end  
    end  
endmodule
